from lxml import etree
import xml.etree.ElementTree as ET

def process_soap_request(xml_data):
    # DTD validation
    dtd = etree.DTD('path_to_your_dtd_file.dtd')
    if not dtd.validate(etree.fromstring(xml_data)):
        raise ValueError("DTD validation failed")

    # Parse the SOAP envelope
    root = ET.fromstring(xml_data)
    
    # Extract the message body
    message_body = None
    for child in root:
        if child.tag.endswith('Body'):
            message_body = child
            break
    
    if message_body is None:
        raise ValueError("SOAP Body not found")
    
    return message_body

# Example usage
xml_data = """
<soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope">
  <soap:Header/>
  <soap:Body>
    <ns1:GetWeatherResponse xmlns:ns1="http://example.com/weather">
      <ns1:Temperature>22</ns1:Temperature>
    </ns1:GetWeatherResponse>
  </soap:Body>
</soap:Envelope>
"""

try:
    message_body = process_soap_request(xml_data)
    print(etree.tostring(message_body, pretty_print=True).decode())
except ValueError as e:
    print(e)